(function(w){"use strict";const ID="prime-factorization",MAX=1000000000000n;function parse(v){const s=String(v??"").replace(/,/g,"").trim();if(!/^\d+$/.test(s))return null;try{return BigInt(s)}catch(_){return null}}function compute(x){let n=parse(x.n);if(n===null||n<1n)return{error:"1 이상의 정수를 입력해 주세요."};if(n>MAX)return{error:"빠르고 안정적인 계산을 위해 1,000,000,000,000 이하의 정수를 입력해 주세요."};if(n===1n)return{factorText:"1",factorCount:0};const parts=[];function take(p){let c=0;while(n%p===0n){n/=p;c++}if(c)parts.push(c===1?p.toString():p.toString()+"^"+c)}take(2n);take(3n);let p=5n,step=2n;while(p*p<=n){take(p);p+=step;step=6n-step}if(n>1n)parts.push(n.toString());return{factorText:parts.join(" × "),factorCount:parts.length}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label for="hm-factor-n">자연수</label><input id="hm-factor-n" class="hm-calc-input" inputmode="numeric" placeholder="예: 360"><p class="hm-calc-hint">1조 이하 자연수의 소인수분해를 지원합니다.</p></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">소인수분해</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const n=root.querySelector("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({n:n.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("소인수분해 결과",api.escapeHTML(r.factorText)));});reset.addEventListener("click",()=>{n.value="";api.setMessage(msg,"");api.clearResult(res);n.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
